using Azure.Messaging.ServiceBus;\nusing Employee.Application.Common.Events;\nusing Employee.Application.Common.Messaging;\nusing Microsoft.Extensions.Hosting;\nusing System.Text.Json;\n\nnamespace Employee.Infrastructure.Messaging.ServiceBus\n{\n    /// <summary>\n    /// Azure Service Bus event subscriber and processor\n    /// </summary>\n    public class ServiceBusEventSubscriber : BackgroundService\n    {\n        private readonly ServiceBusClient _serviceBusClient;\n        private readonly ServiceBusProcessor _processor;\n        private readonly ILogger<ServiceBusEventSubscriber> _logger;\n        private readonly Dictionary<string, Func<string, CancellationToken, Task>> _handlers;\n\n        public ServiceBusEventSubscriber(\n            ServiceBusClient serviceBusClient,\n            ILogger<ServiceBusEventSubscriber> logger,\n            string topicName = \"employee-events\",\n            string subscriptionName = \"employee-service-subscription\")\n        {\n            _serviceBusClient = serviceBusClient;\n            _processor = serviceBusClient.CreateProcessor(topicName, subscriptionName);\n            _logger = logger;\n            _handlers = new Dictionary<string, Func<string, CancellationToken, Task>>();\n        }\n\n        public void RegisterHandler<T>(Func<T, CancellationToken, Task> handler) where T : IntegrationEvent\n        {\n            var eventType = typeof(T).Name;\n            _handlers[eventType] = async (json, cancellationToken) =>\n            {\n                try\n                {\n                    var @event = JsonSerializer.Deserialize<T>(json);\n                    if (@event != null)\n                    {\n                        await handler(@event, cancellationToken);\n                    }\n                }\n                catch (Exception ex)\n                {\n                    _logger.LogError(ex, \"Error handling event of type {EventType}\", eventType);\n                    throw;\n                }\n            };\n        }\n\n        protected override async Task ExecuteAsync(CancellationToken stoppingToken)\n        {\n            _processor.ProcessMessageAsync += ProcessMessageHandler;\n            _processor.ProcessErrorAsync += ProcessErrorHandler;\n\n            await _processor.StartProcessingAsync(stoppingToken);\n\n            _logger.LogInformation(\"Service Bus event subscriber started\");\n\n            while (!stoppingToken.IsCancellationRequested)\n            {\n                await Task.Delay(1000, stoppingToken);\n            }\n\n            await _processor.StopProcessingAsync(stoppingToken);\n        }\n\n        private async Task ProcessMessageHandler(ProcessMessageEventArgs args)\n        {\n            try\n            {\n                var message = args.Message;\n                var body = message.Body.ToString();\n                var eventType = message.Subject ?? message.ApplicationProperties[\"EventType\"]?.ToString();\n\n                _logger.LogInformation(\n                    \"Processing Service Bus message: {MessageId}, EventType: {EventType}\",\n                    message.MessageId,\n                    eventType);\n\n                if (_handlers.TryGetValue(eventType, out var handler))\n                {\n                    await handler(body, args.CancellationToken);\n                    await args.CompleteMessageAsync(args.CancellationToken);\n                }\n                else\n                {\n                    _logger.LogWarning(\"No handler registered for event type: {EventType}\", eventType);\n                    await args.DeadLetterMessageAsync(args.Message, cancellationToken: args.CancellationToken);\n                }\n            }\n            catch (Exception ex)\n            {\n                _logger.LogError(ex, \"Error processing Service Bus message\");\n                await args.AbandonMessageAsync(args.Message, args.CancellationToken);\n            }\n        }\n\n        private Task ProcessErrorHandler(ProcessErrorEventArgs args)\n        {\n            _logger.LogError(\n                args.Exception,\n                \"Service Bus error occurred. Entity: {Entity}, Error: {Error}\",\n                args.EntityPath,\n                args.Exception.Message);\n\n            return Task.CompletedTask;\n        }\n\n        public override async ValueTask DisposeAsync()\n        {\n            await _processor.DisposeAsync();\n            await _serviceBusClient.DisposeAsync();\n            await base.DisposeAsync();\n        }\n    }\n}\n